#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_KMER_LEN 100
#define MAX_EXTENSIONS 4
#define HASH_TABLE_SIZE 10000

typedef struct KmerNode {
    char kmer[MAX_KMER_LEN];
    char left_ext;
    char right_ext;
    bool visited;
    struct KmerNode* next;
} KmerNode;

typedef struct {
    KmerNode** buckets;
    int size;
} HashTable;

unsigned int hash(const char* str, int size) {
    unsigned int hash = 5381;
    int c;
    while ((c = *str++))
        hash = ((hash << 5) + hash) + c;
    return hash % size;
}

HashTable* create_hash_table(int size) {
    HashTable* table = malloc(sizeof(HashTable));
    table->size = size;
    table->buckets = calloc(size, sizeof(KmerNode*));
    return table;
}

void insert_kmer(HashTable* table, const char* kmer, char left_ext, char right_ext) {
    unsigned int index = hash(kmer, table->size);
    KmerNode* new_node = malloc(sizeof(KmerNode));
    strcpy(new_node->kmer, kmer);
    new_node->left_ext = left_ext;
    new_node->right_ext = right_ext;
    new_node->visited = false;
    new_node->next = table->buckets[index];
    table->buckets[index] = new_node;
}

KmerNode* find_kmer(HashTable* table, const char* kmer) {
    unsigned int index = hash(kmer, table->size);
    KmerNode* current = table->buckets[index];
    while (current) {
        if (strcmp(current->kmer, kmer) == 0)
            return current;
        current = current->next;
    }
    return NULL;
}

void extend_contig(HashTable* table, KmerNode* start_node, char* contig, int direction) {
    KmerNode* current = start_node;
    current->visited = true;

    if (direction == 0) { // extend left
        while (current->left_ext != 'F') {
            char prev_kmer[MAX_KMER_LEN];
            int kmer_len = strlen(current->kmer);
            strncpy(prev_kmer, current->kmer, kmer_len - 1);
            prev_kmer[kmer_len - 1] = current->left_ext;
            prev_kmer[kmer_len] = '\0';

            KmerNode* prev_node = find_kmer(table, prev_kmer);
            if (!prev_node || prev_node->visited) break;

            // Prepend character to contig
            memmove(contig + 1, contig, strlen(contig) + 1);
            contig[0] = current->left_ext;
            prev_node->visited = true;
            current = prev_node;
        }
    } else { // extend right
        strcat(contig, current->kmer + 1);
        while (current->right_ext != 'F') {
            char next_kmer[MAX_KMER_LEN];
            int kmer_len = strlen(current->kmer);
            strncpy(next_kmer, current->kmer + 1, kmer_len - 1);
            next_kmer[kmer_len - 1] = current->right_ext;
            next_kmer[kmer_len] = '\0';

            KmerNode* next_node = find_kmer(table, next_kmer);
            if (!next_node || next_node->visited) break;

            strcat(contig, &current->right_ext);
            next_node->visited = true;
            current = next_node;
        }
    }
}

int main() {
    FILE* input = fopen("test", "r");
    if (!input) {
        perror("Failed to open input file");
        return 1;
    }

    HashTable* table = create_hash_table(HASH_TABLE_SIZE);
    char line[256];
    char kmer[MAX_KMER_LEN];
    char left_ext, right_ext;

    // Read input and build hash table
    while (fgets(line, sizeof(line), input)) {
        if (sscanf(line, "%s %c%c", kmer, &left_ext, &right_ext) == 3) {
            insert_kmer(table, kmer, left_ext, right_ext);
        }
    }
    fclose(input);

    FILE* output = fopen("/app/serial.out", "w");
    if (!output) {
        perror("Failed to open output file");
        return 1;
    }

    // Find starting points (nodes with no incoming edges or F left extension)
    for (int i = 0; i < table->size; i++) {
        KmerNode* current = table->buckets[i];
        while (current) {
            if (!current->visited && current->left_ext == 'F') {
                char contig[MAX_KMER_LEN * 100] = {0};
                strcpy(contig, current->kmer);

                // Extend right
                extend_contig(table, current, contig, 1);

                fprintf(output, "%s\n", contig);
            }
            current = current->next;
        }
    }

    // Handle remaining unvisited nodes (circular or isolated components)
    for (int i = 0; i < table->size; i++) {
        KmerNode* current = table->buckets[i];
        while (current) {
            if (!current->visited) {
                char contig[MAX_KMER_LEN * 100] = {0};
                strcpy(contig, current->kmer);

                // Extend in both directions
                extend_contig(table, current, contig, 0);
                extend_contig(table, current, contig, 1);

                fprintf(output, "%s\n", contig);
            }
            current = current->next;
        }
    }

    fclose(output);

    // Cleanup
    for (int i = 0; i < table->size; i++) {
        KmerNode* current = table->buckets[i];
        while (current) {
            KmerNode* temp = current;
            current = current->next;
            free(temp);
        }
    }
    free(table->buckets);
    free(table);

    return 0;
}
EOF
