typedef struct KmerNode {
    char kmer[MAX_KMER_LEN];
    char left_ext;
    char right_ext;
    bool visited;
    pthread_mutex_t lock;
    struct KmerNode* next;
} KmerNode;

typedef struct {
    KmerNode** buckets;
    int size;
