HashTable* create_hash_table(int size) {
    HashTable* table = malloc(sizeof(HashTable));
    table->size = size;
    table->buckets = calloc(size, sizeof(KmerNode*));
    table->bucket_locks = malloc(size * sizeof(pthread_mutex_t));

    for (int i = 0; i < size; i++) {
        pthread_mutex_init(&table->bucket_locks[i], NULL);
    }

    return table;
}

void insert_kmer(HashTable* table, const char* kmer, char left_ext, char right_ext) {
    unsigned int index = hash(kmer, table->size);

    pthread_mutex_lock(&table->bucket_locks[index]);

    KmerNode* new_node = malloc(sizeof(KmerNode));
    strcpy(new_node->kmer, kmer);
    new_node->left_ext = left_ext;
    new_node->right_ext = right_ext;
    new_node->visited = false;
    pthread_mutex_init(&new_node->lock, NULL);
    new_node->next = table->buckets[index];
    table->buckets[index] = new_node;

    pthread_mutex_unlock(&table->bucket_locks[index]);
}

KmerNode* find_kmer(HashTable* table, const char* kmer) {
    unsigned int index = hash(kmer, table->size);

    pthread_mutex_lock(&table->bucket_locks[index]);

    KmerNode* current = table->buckets[index];
    while (current) {
        if (strcmp(current->kmer, kmer) == 0) {
            pthread_mutex_unlock(&table->bucket_locks[index]);
            return current;
        }
        current = current->next;
    }

    pthread_mutex_unlock(&table->bucket_locks[index]);
    return NULL;
}

void extend_contig_parallel(HashTable* table, KmerNode* start_node, char* contig, int direction) {
    KmerNode* current = start_node;
    pthread_mutex_lock(&current->lock);
    current->visited = true;
    pthread_mutex_unlock(&current->lock);

    if (direction == 0) { // extend left
        while (current->left_ext != 'F') {
            char prev_kmer[MAX_KMER_LEN];
            int kmer_len = strlen(current->kmer);
            strncpy(prev_kmer, current->kmer, kmer_len - 1);
            prev_kmer[kmer_len - 1] = current->left_ext;
            prev_kmer[kmer_len] = '\0';

            KmerNode* prev_node = find_kmer(table, prev_kmer);
            if (!prev_node) break;

            pthread_mutex_lock(&prev_node->lock);
            if (prev_node->visited) {
                pthread_mutex_unlock(&prev_node->lock);
                break;
            }
            prev_node->visited = true;
            pthread_mutex_unlock(&prev_node->lock);

            // Prepend character to contig
            memmove(contig + 1, contig, strlen(contig) + 1);
            contig[0] = current->left_ext;
            current = prev_node;
        }
    } else { // extend right
        strcat(contig, current->kmer + 1);
        while (current->right_ext != 'F') {
            char next_kmer[MAX_KMER_LEN];
            int kmer_len = strlen(current->kmer);
            strncpy(next_kmer, current->kmer + 1, kmer_len - 1);
            next_kmer[kmer_len - 1] = current->right_ext;
            next_kmer[kmer_len] = '\0';

            KmerNode* next_node = find_kmer(table, next_kmer);
            if (!next_node) break;

            pthread_mutex_lock(&next_node->lock);
            if (next_node->visited) {
                pthread_mutex_unlock(&next_node->lock);
                break;
            }
            next_node->visited = true;
            pthread_mutex_unlock(&next_node->lock);

            strcat(contig, &current->right_ext);
            current = next_node;
        }
    }
