    int num_threads = data->num_threads;

    // Process a subset of hash buckets
    for (int i = thread_id; i < table->size; i += num_threads) {
        pthread_mutex_lock(&table->bucket_locks[i]);

        KmerNode* current = table->buckets[i];
        while (current) {
            pthread_mutex_lock(&current->lock);
            bool should_process = !current->visited && current->left_ext == 'F';
            pthread_mutex_unlock(&current->lock);

