                // Write to thread-specific output file
                pthread_mutex_lock(data->output_lock);
                fprintf(data->output, "%s\n", contig);
                pthread_mutex_unlock(data->output_lock);
            }
            current = current->next;
        }

        pthread_mutex_unlock(&table->bucket_locks[i]);
    }

    // Handle remaining unvisited nodes
    for (int i = thread_id; i < table->size; i += num_threads) {
        pthread_mutex_lock(&table->bucket_locks[i]);

        KmerNode* current = table->buckets[i];
        while (current) {
            pthread_mutex_lock(&current->lock);
            bool should_process = !current->visited;
            pthread_mutex_unlock(&current->lock);

