    HashTable* table = create_hash_table(HASH_TABLE_SIZE);
    char line[256];
    char kmer[MAX_KMER_LEN];
    char left_ext, right_ext;

    // Read input and build hash table
    while (fgets(line, sizeof(line), input)) {
        if (sscanf(line, "%s %c%c", kmer, &left_ext, &right_ext) == 3) {
            insert_kmer(table, kmer, left_ext, right_ext);
        }
    }
    fclose(input);

    // Create output files for each thread
    char output_filename[256];
    snprintf(output_filename, sizeof(output_filename), "/app/pgen_%d.out", 0);
    FILE* output = fopen(output_filename, "w");
    if (!output) {
        perror("Failed to open output file");
        return 1;
    }

    // For now, use single thread to simulate UPC behavior
    // In real UPC, this would be distributed across threads
    pthread_t threads[MAX_THREADS];
    ThreadData thread_data[MAX_THREADS];
    pthread_mutex_t output_lock;
    pthread_mutex_init(&output_lock, NULL);

    // Create threads
    for (int i = 0; i < MAX_THREADS; i++) {
        thread_data[i].table = table;
        thread_data[i].thread_id = i;
        thread_data[i].num_threads = MAX_THREADS;
        thread_data[i].output = output;
        thread_data[i].output_lock = &output_lock;

        pthread_create(&threads[i], NULL, process_thread, &thread_data[i]);
    }

    // Wait for threads to complete
    for (int i = 0; i < MAX_THREADS; i++) {
        pthread_join(threads[i], NULL);
    }

    fclose(output);
    pthread_mutex_destroy(&output_lock);

    // Cleanup
    for (int i = 0; i < table->size; i++) {
        pthread_mutex_destroy(&table->bucket_locks[i]);
        KmerNode* current = table->buckets[i];
        while (current) {
            KmerNode* temp = current;
            current = current->next;
            pthread_mutex_destroy(&temp->lock);
            free(temp);
        }
    }
    free(table->buckets);
    free(table->bucket_locks);
    free(table);

    return 0;
}
